detailed_optimizations.code_changes:
将j和i循环顺序交换，确保内存连续访问。
修改前：for (i = 1; i < _PB_NX; i++)
          for (j = 0; j < _PB_NY; j++)
修改后：for (j = 0; j < _PB_NY; j++)
          for (i = 1; i < _PB_NX; i++)

对循环进行分块处理，提高缓存利用率。
int block_size = 64; // 根据L1缓存大小调整
for (ii = 1; ii < _PB_NX; ii += block_size)
  for (jj = 0; jj < _PB_NY; jj += block_size)
    for (i = ii; i < min(ii+block_size, _PB_NX); i++)
      for (j = jj; j < min(jj+block_size, _PB_NY); j++)

手动展开内层循环4-8次，减少循环开销。
for (i = 1; i < _PB_NX-3; i+=4) {
    ey[i][j] = ey[i][j] - 0.5*(hz[i][j]-hz[i-1][j]);
    ey[i+1][j] = ey[i+1][j] - 0.5*(hz[i+1][j]-hz[i][j]);
    // ... 继续展开
}
